import React from "react";
import { BrowserRouter, Routes, Route } from "react-router-dom";
import { LanguageProvider } from "./LanguageContext";
import Dashboard from "./components/Dashboard";
import CropRecommendation from "./components/CropRecommendation";
import CropDiseaseDetection from "./components/CropDiseaseDetection";
import AnimalDiseasePredictor from "./components/AnimalDiseasePredictor";

function App() {
  return (
    <LanguageProvider>
      <BrowserRouter>
        <Routes>
          <Route path="/" element={<Dashboard />} />
          <Route path="/recommendation" element={<CropRecommendation />} />
          <Route path="/disease" element={<CropDiseaseDetection />} />
          <Route path="/animal" element={<AnimalDiseasePredictor />} />
        </Routes>
      </BrowserRouter>
    </LanguageProvider>
  );
}

export default App;
